// Run verification commands in parallel.
const [vet, status] = await Promise.all([
  tools.shell_command({
    command: "go vet ./...",
    workdir: "/Users/zchee/go/src/github.com/zchee/spanner-manager",
    timeout_ms: 120000,
  }),
  tools.shell_command({
    command: "git status --short --branch",
    workdir: "/Users/zchee/go/src/github.com/zchee/spanner-manager",
    timeout_ms: 120000,
  }),
]);
text("=== go vet ./... ===\n" + JSON.stringify(vet, null, 2) + "\n=== git status --short --branch ===\n" + JSON.stringify(status, null, 2));

const [nameOnly, vendorSearch, diffStat] = await Promise.all([
  tools.shell_command({
    command: "git diff --name-only -- codegen/generator.go codegen/generator_test.go go.mod go.sum .github/workflows",
    workdir: "/Users/zchee/go/src/github.com/zchee/spanner-manager",
    timeout_ms: 120000,
  }),
  tools.shell_command({
    command: "rg --files vendor 2>/dev/null | rg 'gofumpt|mvdan.cc' || true",
    workdir: "/Users/zchee/go/src/github.com/zchee/spanner-manager",
    timeout_ms: 120000,
  }),
  tools.shell_command({
    command: "git diff --stat -- codegen/generator.go codegen/generator_test.go go.mod go.sum .github/workflows",
    workdir: "/Users/zchee/go/src/github.com/zchee/spanner-manager",
    timeout_ms: 120000,
  }),
]);
text("=== git diff --name-only ===\n" + JSON.stringify(nameOnly, null, 2) + "\n=== vendor search ===\n" + JSON.stringify(vendorSearch, null, 2) + "\n=== git diff --stat ===\n" + JSON.stringify(diffStat, null, 2));

const vendorInfo = await tools.shell_command({
  command: "git ls-files vendor/mvdan.cc/gofumpt | sed -n '1,5p'; printf '\\n-- exists --\\n'; test -d vendor/mvdan.cc/gofumpt && echo yes || echo no",
  workdir: "/Users/zchee/go/src/github.com/zchee/spanner-manager",
  timeout_ms: 120000,
});
text(JSON.stringify(vendorInfo, null, 2));

const ignoreCheck = await tools.shell_command({
  command: "git check-ignore -v vendor/mvdan.cc/gofumpt vendor/mvdan.cc/gofumpt/format/format.go || true",
  workdir: "/Users/zchee/go/src/github.com/zchee/spanner-manager",
  timeout_ms: 120000,
});
text(JSON.stringify(ignoreCheck, null, 2));

const seq = await tools.shell_command({
  command: "set -e; go vet ./...; printf '\\n-- status --\\n'; git status --short --branch",
  workdir: "/Users/zchee/go/src/github.com/zchee/spanner-manager",
  timeout_ms: 120000,
});
text(JSON.stringify(seq, null, 2));
